import React, { useEffect, useState } from 'react';
import CadastroSCM from '../components/CadastroSCM';
import MenuLateral from '../components/MenuLateral';
import { useLocation } from 'react-router-dom';

const statusCores = {
  NOVO: '#1976d2',
  ATIVO: '#388e3c',
  CORRIGIR: '#fbc02d',
  SUSPENSO: '#d32f2f'
};
const statusNomes = {
  NOVO: 'Novo',
  ATIVO: 'Ativo',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspenso'
};

const PaginaCadastroSCM = () => {
  const [cliente, setCliente] = useState(null);
  const location = useLocation();

  useEffect(() => {
    // Tenta obter o cliente do localStorage ou query param (exemplo: /scm/cadastro?id=123)
    const params = new URLSearchParams(location.search);
    const id = params.get('id');
    if (id) {
      fetch(`http://localhost:5000/api/clientes/${id}`)
        .then(async resp => {
          if (!resp.ok) return;
          const data = await resp.json();
          setCliente(data);
        });
    }
  }, [location.search]);

  return (
    <div style={{display:'flex'}}>
      <MenuLateral />
      <div style={{marginLeft:200, flex:1, minHeight:'100vh', background:'#f8f9fb'}}>
        {cliente ? (
          <div style={{marginTop:'40px'}}>
            <CadastroSCM cnpj={cliente.cnpj} razaoSocial={cliente.razaoSocial} />
          </div>
        ) : (
          <CadastroSCM />
        )}
      </div>
    </div>
  );
};

export default PaginaCadastroSCM;
